1	import { describe, it, expect } from "vitest";
2	import { quote } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("Quote — base premiums and fee", () => {
6	    it("empty item list returns premium 5 G (processing fee only)", () => {
7	      expect(quote({ yearsWithMHPCO: 0 }, [])).toBe(5);
8	    });
9	    it.todo("single plain sword (year 0, first contract) returns 115 G (100 base + 10 first-insurance + 5 fee)");
10	    it.todo("single plain amulet (year 0, first contract) returns 71 G (60 base + 6 first-insurance + 5 fee)");
11	    it.todo("single plain staff (year 0, first contract) returns 93 G (80 base + 8 first-insurance + 5 fee)");
12	    it.todo("single plain potion (year 0, first contract) returns 49 G (40 base + 4 first-insurance + 5 fee)");
13	  });
14	
15	  describe("Quote — components and block discount", () => {
16	    it.todo("2 runes returns 60 G (50 base + 5 first-insurance + 5 fee)");
17	    it.todo("3 runes returns 71 G (60 block base + 6 first-insurance + 5 fee)");
18	    it.todo("4 runes returns 115 G (100 base + 10 first-insurance + 5 fee; no block since not exactly 3)");
19	    it.todo("7 runes returns 198 G (175 base + 17.5 first-insurance + 5 fee = 197.5 rounded up)");
20	    it.todo("2 runes + 1 moonstone returns 88 G (75 base + 7.5 first-insurance + 5 fee = 87.5 rounded up; alike means same type)");
21	    it.todo("3 runes + 3 moonstones returns 137 G (120 base from two blocks + 12 first-insurance + 5 fee)");
22	  });
23	
24	  describe("Quote — item-specific modifiers", () => {
25	    it.todo("cursed sword (steel, ench 3, year 0, first contract) returns 165 G (100 + 50 curse + 10 first-insurance + 5 fee)");
26	    it.todo("cursed sword + plain amulet (year 0, first contract) returns 231 G (curse applies only to sword: 100+50+60 base + 10+6 first-ins + 5 fee)");
27	    it.todo("sword with enchantment exactly 5 (year 0) returns 145 G (100 + 30 high-ench + 10 first-ins + 5 fee)");
28	    it.todo("sword with enchantment 4 (year 0) returns 115 G (no high-ench surcharge)");
29	    it.todo("cursed sword with enchantment 5 (year 0) returns 195 G (100 + 50 curse + 30 high-ench + 10 first-ins + 5 fee)");
30	  });
31	
32	  describe("Quote — policy-wide modifiers", () => {
33	    it.todo("2-year customer with plain sword, first contract returns 95 G (100 + 10 first-ins − 20 loyalty + 5 fee)");
34	    it.todo("3-year customer's second quote of cursed sword ench 7 returns 160 G (100 + 50 curse + 30 high-ench + 10 first-ins − 20 loyalty − 15 follow-up + 5 fee)");
35	  });
36	
37	  describe("Claim — standard reimbursement and deductible", () => {
38	    it.todo("steel sword ench 3 damaged 500 G returns payout 400 G and remainingCap 1600 (cap 2000 − 400)");
39	    it.todo("rune damaged 200 G returns payout 100 G and remainingCap 400 (cap 500 − 100; no special clause for components)");
40	    it.todo("dragon attack damages sword 500 G + amulet 300 G returns payout 600 G (deductible per damage event: 400 + 200)");
41	  });
42	
43	  describe("Claim — special reimbursement clauses", () => {
44	    it.todo("steel sword ench 9 damaged 1000 G returns payout 400 G (50% rule then deductible)");
45	    it.todo("dragon-material sword ench 5 damaged 800 G returns payout 700 G (full reimbursement then deductible)");
46	    it.todo("dragon-material sword ench 9 damaged 1000 G returns payout 400 G (both clauses: 50% wins, then deductible)");
47	    it.todo("dragon-material sword ench exactly 8 damaged 1000 G returns payout 400 G (50% applies at threshold)");
48	  });
49	
50	  describe("Claim — cap behavior", () => {
51	    it.todo("sword insured; two successive 1500 G claims: first payout 1400 remainingCap 600, second payout 600 remainingCap 0");
52	    it.todo("cursed sword's cap remains 2000 G (premium modifiers do not raise the cap)");
53	    it.todo("sword + 3 runes: insurance sum 1750 G, cap 3500 G (block discount affects premium only, not insurance sum)");
54	    it.todo("policy with two swords: insurance sum 2000 G, cap 4000 G; both damaged 500 G each returns payout 800 G");
55	    it.todo("payout calculation yielding 350.5 G is rounded down to 350 G (sword ench 9 damaged 901 G: 450.5 − 100 = 350.5 → 350)");
56	  });
57	
58	  describe("CLI — JSON stdin/stdout interface", () => {
59	    it.todo("quote-only scenario via stdin produces {results:[{premium:<int>}]} on stdout");
60	    it.todo("quote-then-claim scenario produces results with {premium} then {payout, remainingCap}");
61	    it.todo("quote with unknown item type ({type:'broomstick'}) exits non-zero, writes error to stderr, writes no results to stdout");
62	    it.todo("claim referencing item type not present in policy exits non-zero with stderr error");
63	    it.todo("claim with negative damage amount (amount: -200) exits non-zero with stderr error");
64	    it.todo("claim with more damage entries of a type than the policy contains (2 sword damages, 1 sword insured) exits non-zero with stderr error");
65	  });
66	});
